1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	export function quote(input: { customer: { yearsWithMHPCO: number; previousContract: boolean }; items: { type: string }[] }): number {
14	  if (input.items.length === 0) return PROCESSING_FEE;
15	  const allRunes = input.items.every((item) => item.type === "rune");
16	  const basePremium =
17	    allRunes && input.items.length === 3
18	      ? 60
19	      : input.items.reduce((sum, item) => sum + BASE_PREMIUM_BY_TYPE[item.type], 0);
20	  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
21	  return Math.ceil(basePremium + firstInsurance + PROCESSING_FEE);
22	}
23	
